import{_ as i}from"./chunks/pricing.xnwHCEuz.js";import{_ as a,o as e,c as t,a2 as n}from"./chunks/framework.BflysNKA.js";const m=JSON.parse('{"title":"计费说明","description":"","frontmatter":{},"headers":[],"relativePath":"pricing/billing.md","filePath":"pricing/billing.md","lastUpdated":1778577020000}'),p={name:"pricing/billing.md"};function s(r,l,o,u,d,h){return e(),t("div",null,[...l[0]||(l[0]=[n('<h1 id="计费说明" tabindex="-1">计费说明 <a class="header-anchor" href="#计费说明" aria-label="Permalink to &quot;计费说明&quot;">​</a></h1><ul><li>余额与消费按元显示</li><li>模型与单价可在模型广场查看</li><li>充值和消费记录在控制台查看</li></ul><p>模型广场：<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">https://xiaolan1.cn/pricing</a></p><p>计费最容易让新手困惑的地方，不是“要不要收费”，而是“为什么同样一句话，不同模型、不同工具、不同上下文长度，费用会不一样”。核心原因通常有三类：</p><ul><li>你选的模型不同</li><li>输入和输出的 token 数不同</li><li>你一次带进去的上下文大小不同</li></ul><p>可以先记一个最实用的判断：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>模型越强、上下文越大、输出越长，费用通常越高</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="看价格先看模型广场" tabindex="-1">看价格先看模型广场 <a class="header-anchor" href="#看价格先看模型广场" aria-label="Permalink to &quot;看价格先看模型广场&quot;">​</a></h2><p>不同模型的价格、能力和可用状态会变化。实际使用前，以模型广场展示为准。</p><p><img src="'+i+`" alt="模型广场 — 浏览全部模型与价格，点击模型名即可复制"></p><p>建议关注：</p><ul><li>模型名称</li><li>输入价格</li><li>输出价格</li><li>是否支持图像、音频、长上下文</li><li>当前是否可用</li></ul><p>第一次接入时，不建议直接按照“最强模型”来选。先拿轻量模型把链路跑通，再根据任务换到更强模型，通常更省钱也更容易排障。</p><p>第一次不确定选什么时，可以按这个顺序走：</p><ol><li>先选一个轻量模型</li><li>发一句“你好”或一个最短测试任务</li><li>看日志里的 token 和扣费</li><li>再决定是否需要切到更强模型</li></ol><h2 id="消耗在哪里看" tabindex="-1">消耗在哪里看 <a class="header-anchor" href="#消耗在哪里看" aria-label="Permalink to &quot;消耗在哪里看&quot;">​</a></h2><p>控制台里的日志和统计页可以看到请求明细。</p><p>常见字段：</p><ul><li>请求时间</li><li>使用的 Key</li><li>调用模型</li><li>输入 Token</li><li>输出 Token</li><li>实际扣费</li><li>请求状态</li></ul><p>如果你按工具拆分 Key，就能很快看出哪个工具消耗最高。</p><p>真正开始长期使用后，最值得看的通常不是“总共花了多少”，而是：</p><ul><li>哪把 Key 消耗最高</li><li>哪个模型消耗最高</li><li>哪一类任务最容易把上下文带大</li></ul><h2 id="为什么同一个任务有时费用差很多" tabindex="-1">为什么同一个任务有时费用差很多 <a class="header-anchor" href="#为什么同一个任务有时费用差很多" aria-label="Permalink to &quot;为什么同一个任务有时费用差很多&quot;">​</a></h2><p>下面这些情况都会明显影响成本：</p><ul><li>把整个仓库、整篇长文一次性丢给模型</li><li>多轮对话带了很长历史</li><li>同时请求多个结果或更大尺寸的图片</li><li>自动化脚本出现重试循环</li></ul><p>所以“模型单价”只是起点，真正的消耗还和你怎么喂上下文、怎么拆任务密切相关。</p><p>举个最常见的差别：</p><ul><li>只发一句“修这段报错”</li><li>把整个仓库、十几段日志和几轮长历史一起发进去</li></ul><p>哪怕用的是同一个模型，后者的 token 也可能明显更高。</p><h2 id="降低成本的做法" tabindex="-1">降低成本的做法 <a class="header-anchor" href="#降低成本的做法" aria-label="Permalink to &quot;降低成本的做法&quot;">​</a></h2><ul><li>日常问答用轻量模型</li><li>复杂代码任务再切强模型</li><li>不要把整个仓库一次性塞给模型</li><li>长文先摘要，再让强模型处理关键段落</li><li>自动化脚本必须设置额度上限</li></ul><p>如果你已经开始同时用多个工具，通常更稳的做法是：</p><ul><li>桌面聊天一把 Key</li><li>CLI 编程一把 Key</li><li>自动化脚本一把 Key</li></ul><p>这样做不只是为了看日志更清楚，也方便你对高消耗场景单独限额。</p><h2 id="先看账户余额-再看-key-限额" tabindex="-1">先看账户余额，再看 Key 限额 <a class="header-anchor" href="#先看账户余额-再看-key-限额" aria-label="Permalink to &quot;先看账户余额，再看 Key 限额&quot;">​</a></h2><p>很多人以为“还有余额”就代表所有请求都应该成功。实际上还要再看一层：</p><ul><li><strong>账户余额</strong>：整个平台账户还剩多少钱</li><li><strong>Key 限额</strong>：这把 Key 被单独限制到什么程度</li></ul><p>因此：</p><ul><li>余额充足，但某把 Key 到达上限时，请求仍会失败</li><li>Key 额度还没满，但账户总余额不足时，请求也会失败</li></ul><p>排障时，最好把钱包和令牌设置一起看。</p><p>也可以简单理解成：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>钱包余额 = 总预算</span></span>
<span class="line"><span>Key 限额 = 某一把 Key 的局部预算</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="余额异常排查" tabindex="-1">余额异常排查 <a class="header-anchor" href="#余额异常排查" aria-label="Permalink to &quot;余额异常排查&quot;">​</a></h2><ol><li>先看日志，按时间倒序查看最近请求。</li><li>按 Key 过滤，找出消耗来源。</li><li>发现异常请求，先禁用对应 Key。</li><li>检查脚本、客户端或自动化任务是否循环调用。</li><li>必要时联系售后，并提供截图和时间范围。</li></ol><p>截图前记得打码完整 Key。</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/guide/recharge">充值</a></li><li><a href="/guide/modify-token">修改令牌设置</a></li><li><a href="/api/models">模型列表</a></li></ul>`,47)])])}const g=a(p,[["render",s]]);export{m as __pageData,g as default};
